import React, { useEffect, useState } from "react";
import AOS from "aos";
import "aos/dist/aos.css";
import './Header.css';
import photo from '../../assets/avatar1.jpg';

function Header(){
    const capiba = useState()

    useEffect(() => {
            AOS.init({ duration: 1000, once: true });
        }, []);

    return (
        <div className="header">
            <div className="profile-content" data-aos="fade-down">
                <img src={photo} alt="foto de perfil" />
                <div className="info">
                    <h3>Ana</h3>
                    <span>Nível Passista</span>
                </div>
            </div>
            <div className="cash" data-aos="fade-down">
                <h3>Saldo capiba</h3>
                <span>C$120</span>
            </div>
        </div>
    )
}

export default Header;
